#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const rootDir = path.resolve(__dirname, '..');
const hooksDir = path.join(rootDir, '.git', 'hooks');
const hookPath = path.join(hooksDir, 'pre-commit');

const script = `#!/bin/sh
# auto-generated by scripts/install-plan-hook.js
node scripts/plan-commit-guard.js
`;

if (!fs.existsSync(hooksDir)) {
  console.error('[plan-hook] .git/hooks not found.');
  process.exit(1);
}

fs.writeFileSync(hookPath, script, { mode: 0o755 });
console.log(`[plan-hook] installed: ${hookPath}`);

